#!/bin/bash
set -u
cd isolate
fail=0
upload() {
  local p="$1"; local u="$2"; local ct="$3"
  for attempt in 1 2 3; do
    if curl --fail --silent --show-error -X PUT -H "Content-Type: $ct" --upload-file "$p" "$u"; then
      return 0
    fi
    sleep 1
  done
  echo "UPLOAD FAILED: $p" >&2
  return 1
}
